SELECT COUNT(DISTINCT user_id) FROM health_data 
WHERE is_deleted = 0 
AND monitor_time BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) FROM service_order 
WHERE is_deleted = 0 
AND created_at BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) FROM service_verification 
WHERE verification_status = 'verified' 
AND created_at BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) FROM emergency_help 
WHERE is_deleted = 0 
AND created_at BETWEEN #{startTime} AND #{endTime}

SELECT AVG(rating) FROM service_evaluation 
WHERE is_deleted = 0 
AND created_at BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(*) FROM health_data 
WHERE is_deleted = 0 
AND DATE(monitor_time) = #{date}

SELECT COUNT(*) FROM health_data 
WHERE is_deleted = 0 
AND YEAR(monitor_time) = #{year} 
AND MONTH(monitor_time) = #{month}

SELECT COUNT(*) FROM health_data 
WHERE health_status = 'abnormal' 
AND is_deleted = 0 
AND YEAR(monitor_time) = #{year} 
AND MONTH(monitor_time) = #{month}
